## Session 2: Hooks Deep Dive

Hooks let you use React features in function components. Mastering their semantics — especially useEffect's dependency model — separates competent React developers from seniors.

### useEffect — The Dependency Array

```tsx
import { useState, useEffect, useRef, useMemo, useCallback } from 'react';

// No dependency array: runs after EVERY render
useEffect(() => { document.title = `Count: ${count}`; });

// Empty array: runs only after mount
useEffect(() => {
  fetchInitialData();
}, []);

// Specific deps: runs when those values change
useEffect(() => {
  const subscription = subscribe(userId);
  // Cleanup: runs before next effect OR on unmount
  return () => subscription.unsubscribe();
}, [userId]);

// Correct data fetching pattern with cleanup
const [data, setData] = useState<User | null>(null);
const [error, setError] = useState<string | null>(null);
const [loading, setLoading] = useState(false);

useEffect(() => {
  if (!userId) return;
  let cancelled = false;   // prevent state update on unmounted component

  setLoading(true);
  setError(null);

  fetchUser(userId)
    .then(user => { if (!cancelled) setData(user); })
    .catch(err  => { if (!cancelled) setError(err.message); })
    .finally(()  => { if (!cancelled) setLoading(false); });

  return () => { cancelled = true; };
}, [userId]);
```

### useRef

```tsx
// Ref does NOT cause re-render when changed
const countRef = useRef(0); // mutable container: { current: 0 }

// DOM element ref
const inputRef = useRef<HTMLInputElement>(null);
const focusInput = () => inputRef.current?.focus();

// Storing previous value
function usePrevious<T>(value: T): T | undefined {
  const ref = useRef<T>();
  useEffect(() => { ref.current = value; }); // updates after render
  return ref.current; // returns previous render's value
}

// Stable callback ref pattern (no stale closures)
function useLatestRef<T>(value: T) {
  const ref = useRef(value);
  useEffect(() => { ref.current = value; });
  return ref;
}
```

### useMemo and useCallback

```tsx
// useMemo: cache expensive computations
const sortedUsers = useMemo(
  () => [...users].sort((a, b) => a.name.localeCompare(b.name)),
  [users] // recompute only when users changes
);

// useCallback: stable function reference
// Without useCallback, handleDelete is a new function every render
// causing UserRow (with React.memo) to re-render unnecessarily
const handleDelete = useCallback(
  (id: string) => deleteUser(id).then(() => refetch()),
  [deleteUser, refetch] // only recreate when these change
);

// React.memo: skip re-render if props are shallowly equal
const UserRow = React.memo(({ user, onDelete }: UserRowProps) => (
  <tr>
    <td>{user.name}</td>
    <td><button onClick={() => onDelete(user.id)}>Delete</button></td>
  </tr>
));
```

### Custom Hooks

```tsx
// Custom hook: encapsulates effect, state, and logic
function useFetch<T>(url: string | null) {
  const [state, setState] = useState<{
    data: T | null;
    loading: boolean;
    error: string | null;
  }>({ data: null, loading: false, error: null });

  useEffect(() => {
    if (!url) return;
    let cancelled = false;
    setState(s => ({ ...s, loading: true, error: null }));

    fetch(url)
      .then(r => { if (!r.ok) throw new Error(`HTTP ${r.status}`); return r.json(); })
      .then(data => { if (!cancelled) setState({ data, loading: false, error: null }); })
      .catch(err  => { if (!cancelled) setState({ data: null, loading: false, error: err.message }); });

    return () => { cancelled = true; };
  }, [url]);

  return state;
}

// Usage
const { data: user, loading, error } = useFetch<User>(userId ? `/api/users/${userId}` : null);

// useLocalStorage hook
function useLocalStorage<T>(key: string, initialValue: T) {
  const [value, setValue] = useState<T>(() => {
    try {
      const stored = localStorage.getItem(key);
      return stored ? (JSON.parse(stored) as T) : initialValue;
    } catch { return initialValue; }
  });

  const set = useCallback((newValue: T | ((prev: T) => T)) => {
    setValue(prev => {
      const resolved = typeof newValue === 'function'
        ? (newValue as (prev: T) => T)(prev)
        : newValue;
      localStorage.setItem(key, JSON.stringify(resolved));
      return resolved;
    });
  }, [key]);

  return [value, set] as const;
}
```

### Interview Insight

"Why does adding a function to useEffect deps cause an infinite loop?" — If you define a function inside the component body and add it to deps, each render creates a new function reference, the effect sees a changed dep, runs again, triggers a re-render, which creates a new function... use useCallback or move the function outside the component.

