## Session 3: State Management

Choosing the right state management strategy is a core architectural decision. The rule: start with the simplest solution and add complexity only when needed.

### React Context — When and How

```tsx
// Context pattern: separate state from dispatch to avoid unnecessary re-renders
interface ThemeState { mode: 'light' | 'dark'; primaryColor: string; }
type ThemeAction = { type: 'TOGGLE_MODE' } | { type: 'SET_COLOR'; color: string };

const ThemeStateContext = React.createContext<ThemeState | null>(null);
const ThemeDispatchContext = React.createContext<React.Dispatch<ThemeAction> | null>(null);

function themeReducer(state: ThemeState, action: ThemeAction): ThemeState {
  switch (action.type) {
    case 'TOGGLE_MODE': return { ...state, mode: state.mode === 'light' ? 'dark' : 'light' };
    case 'SET_COLOR':   return { ...state, primaryColor: action.color };
    default:            return state;
  }
}

export function ThemeProvider({ children }: { children: React.ReactNode }) {
  const [state, dispatch] = useReducer(themeReducer, { mode: 'light', primaryColor: '#6366f1' });
  return (
    <ThemeStateContext.Provider value={state}>
      <ThemeDispatchContext.Provider value={dispatch}>
        {children}
      </ThemeDispatchContext.Provider>
    </ThemeStateContext.Provider>
  );
}

// Custom hooks for consumers — never expose raw context
export function useTheme() {
  const ctx = useContext(ThemeStateContext);
  if (!ctx) throw new Error('useTheme must be inside ThemeProvider');
  return ctx;
}
export function useThemeDispatch() {
  const ctx = useContext(ThemeDispatchContext);
  if (!ctx) throw new Error('useThemeDispatch must be inside ThemeProvider');
  return ctx;
}
```

### Zustand — Minimal Global State

```tsx
import { create } from 'zustand';
import { persist, devtools } from 'zustand/middleware';

interface CartItem { id: string; name: string; price: number; quantity: number; }

interface CartStore {
  items: CartItem[];
  addItem: (item: Omit<CartItem, 'quantity'>) => void;
  removeItem: (id: string) => void;
  updateQuantity: (id: string, quantity: number) => void;
  clearCart: () => void;
  total: () => number;
}

const useCartStore = create<CartStore>()(
  devtools(
    persist(
      (set, get) => ({
        items: [],

        addItem: (item) => set(state => {
          const existing = state.items.find(i => i.id === item.id);
          if (existing) {
            return { items: state.items.map(i =>
              i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i
            )};
          }
          return { items: [...state.items, { ...item, quantity: 1 }] };
        }),

        removeItem: (id) => set(state => ({
          items: state.items.filter(i => i.id !== id)
        })),

        updateQuantity: (id, quantity) => set(state => ({
          items: quantity <= 0
            ? state.items.filter(i => i.id !== id)
            : state.items.map(i => i.id === id ? { ...i, quantity } : i)
        })),

        clearCart: () => set({ items: [] }),

        total: () => get().items.reduce((sum, i) => sum + i.price * i.quantity, 0)
      }),
      { name: 'cart-storage' } // persists to localStorage
    )
  )
);

// Selective subscription — only re-renders when item count changes
const itemCount = useCartStore(state => state.items.length);
```

### Redux Toolkit

```typescript
import { createSlice, createAsyncThunk, configureStore } from '@reduxjs/toolkit';

// Async thunk
export const fetchProducts = createAsyncThunk(
  'products/fetchAll',
  async (_, { rejectWithValue }) => {
    try {
      const res = await fetch('/api/products');
      if (!res.ok) throw new Error(`HTTP ${res.status}`);
      return await res.json() as Product[];
    } catch (err) {
      return rejectWithValue((err as Error).message);
    }
  }
);

interface ProductsState {
  items: Product[];
  loading: boolean;
  error: string | null;
}

const productsSlice = createSlice({
  name: 'products',
  initialState: { items: [], loading: false, error: null } as ProductsState,
  reducers: {
    addProduct(state, action: { payload: Product }) {
      state.items.push(action.payload); // Immer allows mutation syntax
    },
    removeProduct(state, action: { payload: string }) {
      state.items = state.items.filter(p => p.id !== action.payload);
    }
  },
  extraReducers(builder) {
    builder
      .addCase(fetchProducts.pending,  (state) => { state.loading = true; state.error = null; })
      .addCase(fetchProducts.fulfilled, (state, action) => {
        state.loading = false;
        state.items = action.payload;
      })
      .addCase(fetchProducts.rejected, (state, action) => {
        state.loading = false;
        state.error = action.payload as string;
      });
  }
});
```

