## Session 4: React Patterns

React patterns solve recurring problems: sharing logic, flexible composition, and inversion of control. Modern React prefers hooks and composition over HOCs and render props, but you must understand all of them.

### Higher-Order Components (HOC)

```tsx
// HOC: function that takes a component and returns an enhanced component
function withAuth<P extends object>(WrappedComponent: React.ComponentType<P>) {
  const displayName = WrappedComponent.displayName || WrappedComponent.name;

  const WithAuth = (props: P) => {
    const { user, isLoading } = useAuth();
    if (isLoading) return <Spinner />;
    if (!user) return <Navigate to="/login" />;
    return <WrappedComponent {...props} />;
  };

  WithAuth.displayName = `withAuth(${displayName})`;
  return WithAuth;
}

// Usage
const ProtectedDashboard = withAuth(Dashboard);
```

### Render Props

```tsx
// Render prop: component accepts a function as a prop
interface MousePosition { x: number; y: number; }

const MouseTracker = ({ render }: { render: (pos: MousePosition) => React.ReactNode }) => {
  const [position, setPosition] = useState<MousePosition>({ x: 0, y: 0 });

  useEffect(() => {
    const handler = (e: MouseEvent) => setPosition({ x: e.clientX, y: e.clientY });
    window.addEventListener('mousemove', handler);
    return () => window.removeEventListener('mousemove', handler);
  }, []);

  return <>{render(position)}</>;
};

// Usage
<MouseTracker render={({ x, y }) => <div>Mouse: {x}, {y}</div>} />

// Modern equivalent: custom hook (much simpler)
function useMousePosition() {
  const [position, setPosition] = useState({ x: 0, y: 0 });
  useEffect(() => {
    const handler = (e: MouseEvent) => setPosition({ x: e.clientX, y: e.clientY });
    window.addEventListener('mousemove', handler);
    return () => window.removeEventListener('mousemove', handler);
  }, []);
  return position;
}
```

### Compound Components

```tsx
// Compound components: related components that share implicit state via Context
interface TabsContextType {
  activeTab: string;
  setActiveTab: (id: string) => void;
}
const TabsContext = React.createContext<TabsContextType | null>(null);

function Tabs({ defaultTab, children }: { defaultTab: string; children: React.ReactNode }) {
  const [activeTab, setActiveTab] = useState(defaultTab);
  return (
    <TabsContext.Provider value={{ activeTab, setActiveTab }}>
      <div className="tabs">{children}</div>
    </TabsContext.Provider>
  );
}

function TabList({ children }: { children: React.ReactNode }) {
  return <div role="tablist" className="tab-list">{children}</div>;
}

function Tab({ id, children }: { id: string; children: React.ReactNode }) {
  const ctx = useContext(TabsContext)!;
  return (
    <button
      role="tab"
      aria-selected={ctx.activeTab === id}
      onClick={() => ctx.setActiveTab(id)}
    >
      {children}
    </button>
  );
}

function TabPanel({ id, children }: { id: string; children: React.ReactNode }) {
  const ctx = useContext(TabsContext)!;
  if (ctx.activeTab !== id) return null;
  return <div role="tabpanel">{children}</div>;
}

Tabs.List  = TabList;
Tabs.Tab   = Tab;
Tabs.Panel = TabPanel;

// Usage — clean, declarative API
<Tabs defaultTab="profile">
  <Tabs.List>
    <Tabs.Tab id="profile">Profile</Tabs.Tab>
    <Tabs.Tab id="settings">Settings</Tabs.Tab>
  </Tabs.List>
  <Tabs.Panel id="profile"><ProfileContent /></Tabs.Panel>
  <Tabs.Panel id="settings"><SettingsContent /></Tabs.Panel>
</Tabs>
```

### Composition Patterns

```tsx
// Slot pattern using children and named props
const Modal = ({
  title,
  footer,
  children,
  onClose
}: {
  title: React.ReactNode;
  footer?: React.ReactNode;
  children: React.ReactNode;
  onClose: () => void;
}) => (
  <div role="dialog" aria-modal className="modal">
    <header>{title}<button onClick={onClose}>×</button></header>
    <main>{children}</main>
    {footer && <footer>{footer}</footer>}
  </div>
);

// Usage — each concern in its place
<Modal
  title={<h2>Confirm Deletion</h2>}
  footer={<><Button onClick={cancel}>Cancel</Button><Button onClick={confirm}>Delete</Button></>}
  onClose={close}
>
  <p>Are you sure you want to delete this item?</p>
</Modal>
```

