The App Router (introduced in Next.js 13, stable in 14) is a fundamental shift in how React applications are structured. React Server Components run exclusively on the server; Client Components hydrate in the browser.

### File Conventions

```
app/
  layout.tsx           — root layout: persistent shell, wraps all routes
  page.tsx             — / route
  loading.tsx          — automatic Suspense wrapper for this segment
  error.tsx            — error boundary for this segment ('use client')
  not-found.tsx        — shown when notFound() is called
  globals.css
  (auth)/              — route group: groups routes without affecting URL
    login/page.tsx     — /login
    register/page.tsx  — /register
  dashboard/
    layout.tsx         — nested layout for /dashboard/*
    page.tsx           — /dashboard
    analytics/
      page.tsx         — /dashboard/analytics
  products/
    [id]/              — dynamic segment
      page.tsx         — /products/:id
    [...slug]/page.tsx — catch-all: /products/a/b/c
```

### Server vs Client Components

```tsx
// Server Component (default — no 'use client')
// Can: async/await, access DB directly, keep secrets on server
// Cannot: useState, useEffect, event handlers, browser APIs
async function ProductPage({ params }: { params: Promise<{ id: string }> }) {
  const { id } = await params;
  const product = await db.product.findUnique({ where: { id } });
  if (!product) notFound();

  return (
    <div>
      <h1>{product.name}</h1>
      <p>${product.price}</p>
      {/* Client Component for interactivity */}
      <AddToCartButton productId={product.id} />
    </div>
  );
}

// Client Component — interactive leaf nodes
'use client';
import { useState } from 'react';
import { useCartStore } from '@/store/cart';

function AddToCartButton({ productId }: { productId: string }) {
  const [added, setAdded] = useState(false);
  const addItem = useCartStore(s => s.addItem);

  const handleClick = async () => {
    addItem({ id: productId });
    setAdded(true);
    setTimeout(() => setAdded(false), 2000);
  };

  return (
    <button onClick={handleClick}>
      {added ? 'Added!' : 'Add to Cart'}
    </button>
  );
}
```

