## Session 6: Data Fetching in Next.js

Next.js App Router provides multiple data fetching strategies. Choosing the right one for each page segment is a key architectural decision.

### Fetch Caching Strategies

```tsx
// Static (SSG) — fetch at build time, cache forever
// Use for: marketing pages, documentation, content that rarely changes
async function fetchProducts() {
  const res = await fetch('https://api.example.com/products', {
    cache: 'force-cache' // default in Server Components
  });
  return res.json();
}

// ISR — revalidate every N seconds
// Use for: product listings, blog posts, prices — change occasionally
async function fetchFeaturedProducts() {
  const res = await fetch('https://api.example.com/featured', {
    next: { revalidate: 3600 } // stale-while-revalidate every 1 hour
  });
  return res.json();
}

// SSR — no caching, fresh on every request
// Use for: user-specific data, real-time dashboards, personalized content
async function fetchUserOrders(userId: string) {
  const res = await fetch(`https://api.example.com/users/${userId}/orders`, {
    cache: 'no-store'
  });
  return res.json();
}

// On-demand revalidation
import { revalidatePath, revalidateTag } from 'next/cache';

// After a mutation, invalidate specific pages
revalidatePath('/products');              // revalidate the /products page
revalidatePath('/products/[id]', 'page'); // revalidate all product detail pages
revalidateTag('products');                // revalidate all fetches tagged 'products'
```

### Server Actions — Mutations

```tsx
// app/actions/posts.ts
'use server';
import { revalidatePath } from 'next/cache';
import { redirect } from 'next/navigation';
import { z } from 'zod';

const PostSchema = z.object({
  title: z.string().min(1).max(200),
  content: z.string().min(10),
  published: z.boolean().default(false)
});

export async function createPost(prevState: unknown, formData: FormData) {
  const validatedFields = PostSchema.safeParse({
    title: formData.get('title'),
    content: formData.get('content'),
    published: formData.get('published') === 'on'
  });

  if (!validatedFields.success) {
    return { errors: validatedFields.error.flatten().fieldErrors };
  }

  const post = await db.post.create({ data: validatedFields.data });
  revalidatePath('/posts');
  redirect(`/posts/${post.id}`);
}

// Client Component using the Server Action
'use client';
import { useFormState, useFormStatus } from 'react-dom';
import { createPost } from '@/actions/posts';

function SubmitButton() {
  const { pending } = useFormStatus();
  return <button type="submit" disabled={pending}>{pending ? 'Creating...' : 'Create Post'}</button>;
}

export function CreatePostForm() {
  const [state, formAction] = useFormState(createPost, null);
  return (
    <form action={formAction}>
      <input name="title" />
      {state?.errors?.title && <p>{state.errors.title[0]}</p>}
      <textarea name="content" />
      <SubmitButton />
    </form>
  );
}
